import play.api.libs.json.Json
import play.api.mvc._

class OrdersController extends Controller {

  def getOrderById(orderId: Long) = Action.async { implicit request =>
    // Query database to get order details by orderId
    val order = Order.find(orderId)

    order match {
      case Some(o) => Ok(Json.toJson(o))
      case None => NotFound(Json.obj("message" -> "Order not found"))
    }
  }

